import React from "react";
import "./TileList.css";

export const TileList = ({tiles}) => {
  return (
    <div>
      {tiles.map((tile, index) => {
        const {name, ...description} = tile;
        return (
          <Tile 
          key={index} 
          name={name} 
          description={description} />
        );
})}
    </div>
  );
};
